/**
 * Validation helper module.
 * Each validator returns an array of error strings (empty = valid).
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user id value (must be a positive integer).
 * Accepts numbers and numeric strings (e.g. route params arrive as strings).
 *
 * @param {*}      value - The raw value to check.
 * @param {string} field - Field label used in error messages.
 * @returns {string[]} Array of validation error messages.
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`"${field}" is required`);
    return errors; // no point checking further
  }

  const num = Number(value);

  if (!Number.isFinite(num) || !Number.isInteger(num)) {
    errors.push(`"${field}" must be a numeric integer`);
  } else if (num <= 0) {
    errors.push(`"${field}" must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name value.
 * Rules: required, must be a string, length 1–100 characters.
 *
 * @param {*}      value - The raw value to check.
 * @param {string} field - Field label used in error messages.
 * @returns {string[]} Array of validation error messages.
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`"${field}" must be at most 100 characters (received ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email value.
 * Rules: required, must be a string, valid email format, max 254 characters.
 *
 * @param {*}      value - The raw value to check.
 * @param {string} field - Field label used in error messages.
 * @returns {string[]} Array of validation error messages.
 */
function validateEmail(value, field = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`"${field}" is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`"${field}" must be a string`);
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length === 0) {
    errors.push(`"${field}" must not be empty`);
    return errors;
  }

  if (trimmed.length > 254) {
    errors.push(`"${field}" must be at most 254 characters (received ${trimmed.length})`);
  }

  if (!EMAIL_REGEX.test(trimmed)) {
    errors.push(`"${field}" must be a valid email address`);
  }

  return errors;
}

/**
 * Validate the body of a POST /users request.
 * Required: name, email.
 *
 * @param {object} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUser(body) {
  const errors = [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
  return { valid: errors.length === 0, errors };
}

/**
 * Validate the body of a PUT /users/:id request.
 * Required: name, email.  The :id param is validated separately via validateRouteId.
 *
 * @param {object} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUpdateUser(body) {
  const errors = [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
  return { valid: errors.length === 0, errors };
}

/**
 * Validate a route parameter that should be a positive integer id.
 *
 * @param {string} paramValue - req.params.id (always a string from Express)
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateRouteId(paramValue) {
  const errors = validateId(paramValue, 'id');
  return { valid: errors.length === 0, errors };
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
