/**
 * Validation helper module.
 * Each validator returns an array of error strings (empty = valid).
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const MAX_EMAIL_LENGTH = 254;
const MIN_NAME_LENGTH = 1;
const MAX_NAME_LENGTH = 100;

/**
 * Validate a user ID supplied as a route parameter or body field.
 * Accepts integers and numeric strings; rejects floats, NaN, etc.
 *
 * @param {*} value
 * @param {string} [field='id']
 * @returns {string[]} validation errors
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`'${field}' is required`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`'${field}' must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a name field.
 *
 * @param {*} value
 * @param {string} [field='name']
 * @returns {string[]} validation errors
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`'${field}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${field}' must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < MIN_NAME_LENGTH) {
    errors.push(
      `'${field}' must be at least ${MIN_NAME_LENGTH} character(s) long`
    );
  }

  if (trimmed.length > MAX_NAME_LENGTH) {
    errors.push(
      `'${field}' must be no longer than ${MAX_NAME_LENGTH} characters`
    );
  }

  return errors;
}

/**
 * Validate an email field.
 *
 * @param {*} value
 * @param {string} [field='email']
 * @returns {string[]} validation errors
 */
function validateEmail(value, field = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`'${field}' is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`'${field}' must be a string`);
    return errors;
  }

  if (value.length > MAX_EMAIL_LENGTH) {
    errors.push(
      `'${field}' must be no longer than ${MAX_EMAIL_LENGTH} characters`
    );
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`'${field}' must be a valid email address`);
  }

  return errors;
}

/**
 * Validate the full user body payload (name + email).
 *
 * @param {object} body
 * @returns {string[]} combined validation errors
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate a numeric ID coming from a URL route parameter.
 * Route params are always strings, so coercion is expected.
 *
 * @param {string} paramValue  req.params.id (always a string)
 * @returns {string[]} validation errors
 */
function validateIdParam(paramValue) {
  return validateId(paramValue, 'id');
}

/**
 * Send a 400 response with a structured list of validation errors.
 * Exported so route handlers can call it directly.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationError(res, errors) {
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validateIdParam,
  sendValidationError,
};

