/**
 * validation.js
 * Reusable input-validation helpers for API route handlers.
 *
 * Every validator returns an array of human-readable error strings.
 * An empty array means the input is valid.
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Verify that every key listed in `fields` is present and not blank/null
 * on the `data` object.
 *
 * @param {Object}   data   - The request body (or params) to inspect.
 * @param {string[]} fields - Names of required fields.
 * @returns {string[]} Errors found (empty ⇒ all present).
 */
function validateRequired(data, fields) {
  const errors = [];
  for (const field of fields) {
    const value = data[field];
    if (value === undefined || value === null || value === '') {
      errors.push(`'${field}' is required.`);
    }
  }
  return errors;
}

/**
 * Verify that `value` is a finite integer (or a string that converts to one).
 * Used primarily for URL / query-string id parameters.
 *
 * @param {*}      value     - The raw value to check.
 * @param {string} fieldName - Label used in error messages.
