'use strict';

const express = require('express');
const {
  validateMiddleware,
  validateIdParam,
  validateCreateUser,
  validateUpdateUser,
} = require('./validation');

const app = express();

// Parse JSON request bodies
app.use(express.json());

// ---------------------------------------------------------------------------
// In-memory "database"
// ---------------------------------------------------------------------------
let users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];
let nextId = 3;

// ---------------------------------------------------------------------------
// Health check
// ---------------------------------------------------------------------------

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// ---------------------------------------------------------------------------
// GET /users  — list all users
// ---------------------------------------------------------------------------

app.get('/users', (req, res) => {
  res.json(users);
});

// ---------------------------------------------------------------------------
// GET /users/:id  — fetch a single user
//
// Validation:
//   • id must be present
//   • id must be a positive integer
// ---------------------------------------------------------------------------

app.get(
  '/users/:id',
  validateMiddleware((params) => validateIdParam(params)),
  (req, res) => {
    const id = Number(req.params.id);
    const user = users.find((u) => u.id === id);
    if (!user) {
      return res.status(404).json({ error: `User with id ${id} not found.` });
    }
    res.json(user);
  }
);

// ---------------------------------------------------------------------------
// POST /users  — create a new user
//
// Validation:
//   • name is required, must be a string, 1–100 characters
//   • email is required, must be a string, max 254 characters, valid format
// ---------------------------------------------------------------------------

app.post(
  '/users',
  validateMiddleware((params, body) => validateCreateUser(body)),
  (req, res) => {
    const { name, email } = req.body;
    const newUser = { id: nextId++, name, email };
    users.push(newUser);
    res.status(201).json(newUser);
  }
);

// ---------------------------------------------------------------------------
// PUT /users/:id  — replace an existing user
//
// Validation:
//   • id must be present and a positive integer
//   • name is required, must be a string, 1–100 characters
//   • email is required, must be a string, max 254 characters, valid format
// ---------------------------------------------------------------------------

app.put(
  '/users/:id',
  validateMiddleware((params, body) => validateUpdateUser(params, body)),
  (req, res) => {
    const id = Number(req.params.id);
    const index = users.findIndex((u) => u.id === id);
    if (index === -1) {
      return res.status(404).json({ error: `User with id ${id} not found.` });
    }
    const { name, email } = req.body;
    users[index] = { id, name, email };
    res.json(users[index]);
  }
);

// ---------------------------------------------------------------------------
// DELETE /users/:id  — remove a user
//
// Validation:
//   • id must be present and a positive integer
// ---------------------------------------------------------------------------

app.delete(
  '/users/:id',
  validateMiddleware((params) => validateIdParam(params)),
  (req, res) => {
    const id = Number(req.params.id);
    const index = users.findIndex((u) => u.id === id);
    if (index === -1) {
      return res.status(404).json({ error: `User with id ${id} not found.` });
    }
    users.splice(index, 1);
    res.status(204).send();
  }
);

// ---------------------------------------------------------------------------
// Start server
// ---------------------------------------------------------------------------

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

