// validation.js — reusable input validation helpers

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validates a route/query `id` parameter.
 * Rules: required, must be a whole positive integer.
 * @param {*} id  - raw value from req.params or req.query
 * @returns {string[]} array of error messages (empty = valid)
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no point checking further
  }

  const parsed = Number(id);
  if (!Number.isFinite(parsed) || !Number.isInteger(parsed) || parsed <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validates the `name` field from a request body.
 * Rules: required, must be a string, length 1–100 characters.
 * @param {*} name - raw value from req.body
 * @returns {string[]} array of error messages (empty = valid)
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors; // length checks are meaningless on a non-string
  }

  if (name.length < 1) {
    errors.push('name must be at least 1 character');
  } else if (name.length > 100) {
    errors.push('name must be at most 100 characters');
  }

  return errors;
}

/**
 * Validates the `email` field from a request body.
 * Rules: required, must be a string, max 254 characters, valid email format.
 * @param {*} email - raw value from req.body
 * @returns {string[]} array of error messages (empty = valid)
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > 254) {
    errors.push('email must be at most 254 characters');
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validates a full user body (name + email together).
 * Collects all field errors so the caller receives one complete list.
 * @param {object} body - req.body
 * @returns {string[]} combined array of error messages (empty = valid)
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

