 * Convenience: returns a standardised 400 response payload.
 * @param {string[]} errors
 * @returns {{ error: string, details: string[] }}
 */
function badRequest(errors) {
  return { error: 'Validation failed', details: errors };
}

module.exports = { validateId, validateName, validateEmail, validateUserBody, badRequest };

