37	 *   - length: 1–100 characters
38	 */
39	function validateName(value, required = true) {
40	  if (value === undefined || value === null) {
41	    return required ? '"name" is required' : null;
42	  }
43	  if (typeof value !== 'string') {
44	    return '"name" must be a string';
45	  }
46	  const trimmed = value.trim();
47	  if (trimmed.length === 0) {
48	    return '"name" must not be blank';
49	  }
