57	 * Validates an email field:
58	 *   - must be present (when required)
59	 *   - must be a string
60	 *   - must match a standard email format
61	 *   - length: 1–254 characters (RFC 5321 maximum)
62	 */
63	function validateEmail(value, required = true) {
64	  if (value === undefined || value === null) {
65	    return required ? '"email" is required' : null;
66	  }
67	  if (typeof value !== 'string') {
68	    return '"email" must be a string';
69	  }
